# Exhaustively check graph-combinatorial claims for small n.
from itertools import combinations
def comp_connected(n, edges):
    # vertices 0..n-1; complement edges among pairs not in edges
    comp = {i:set() for i in range(n)}
    for i,j in combinations(range(n),2):
        if (min(i,j),max(i,j)) not in edges:
            comp[i].add(j); comp[j].add(i)
    seen=set([0]); stack=[0]
    while stack:
        u=stack.pop()
        for v in comp[u]:
            if v not in seen:
                seen.add(v); stack.append(v)
    return len(seen)==n, comp
def check(n):
    bad=[]
    pairs=list(combinations(range(n),2))
    for mask in range(1<<len(pairs)):
        edges=set()
        for k,p in enumerate(pairs):
            if mask>>k &1: edges.add(p)
        conn, comp = comp_connected(n, edges)
        if not conn: continue
        for v in range(n):
            C=comp[v]
            if not C:
                bad.append(("emptyC",edges,v))
            if len(C)==1:
                r=next(iter(C))
                found=False
                for s in range(n):
                    if s!=v and s!=r and (min(s,v),max(s,v)) in edges and (min(s,r),max(s,r)) not in edges:
                        found=True
                if not found:
                    bad.append(("nos",edges,v,r,comp))
        inter=set(range(n))
        for v in range(n):
            L={u for u in range(n) if u!=v and (min(u,v),max(u,v)) in edges}
            inter &= L
        if inter:
            bad.append(("linkinter",edges,inter))
    return bad
for n in range(3,7):
    bad=check(n)
    print(n, len(bad))
